"use client"

import { FormEvent, useCallback, useEffect, useState } from "react"
import Link from "next/link"
import { MobileNav } from "@/components/mobile-nav"
import {
  getPortalToken,
  portalDeactivate,
  portalLogin,
  portalMe,
  setPortalToken,
  type PortalLicense,
} from "@/lib/portal"
import { SALES_EMAIL } from "@/lib/config"

function formatDate(iso: string | null) {
  if (!iso) return "Sem expiração"
  try {
    return new Date(iso).toLocaleDateString("pt-BR", {
      day: "2-digit",
      month: "short",
      year: "numeric",
    })
  } catch {
    return iso
  }
}

function planLabel(plan: string) {
  const map: Record<string, string> = {
    pro: "Pro",
    team: "Equipe",
    perpetual: "Perpétua",
    trial: "Avaliação",
  }
  return map[plan] || plan
}

export default function ContaPage() {
  const [email, setEmail] = useState("")
  const [key, setKey] = useState("")
  const [token, setToken] = useState<string | null>(null)
  const [license, setLicense] = useState<PortalLicense | null>(null)
  const [error, setError] = useState<string | null>(null)
  const [loading, setLoading] = useState(false)
  const [booting, setBooting] = useState(true)
  const [pendingDevice, setPendingDevice] = useState<string | null>(null)

  const loadMe = useCallback(async (tok: string) => {
    const data = await portalMe(tok)
    setLicense(data.license)
    setToken(tok)
  }, [])

  useEffect(() => {
    const existing = getPortalToken()
    if (!existing) {
      setBooting(false)
      return
    }
    loadMe(existing)
      .catch(() => {
        setPortalToken(null)
        setToken(null)
        setLicense(null)
      })
      .finally(() => setBooting(false))
  }, [loadMe])

  async function onSubmit(e: FormEvent) {
    e.preventDefault()
    setError(null)
    setLoading(true)
    try {
      const data = await portalLogin(email.trim(), key.trim())
      setPortalToken(data.token)
      setToken(data.token)
      setLicense(data.license)
    } catch (err) {
      setError(err instanceof Error ? err.message : "Não foi possível entrar.")
    } finally {
      setLoading(false)
    }
  }

  function logout() {
    setPortalToken(null)
    setToken(null)
    setLicense(null)
    setPendingDevice(null)
  }

  async function deactivate(device: string) {
    if (!token) return
    setError(null)
    setLoading(true)
    try {
      const data = await portalDeactivate(token, device)
      setLicense(data.license)
      setPendingDevice(null)
    } catch (err) {
      setError(err instanceof Error ? err.message : "Falha ao desativar.")
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="bg-[#F5F4F0] text-[#111] min-h-screen font-sans antialiased">
      <MobileNav />
      <main className="pt-28 pb-20 px-6 md:px-12">
        <div className="max-w-xl mx-auto">
          <p className="text-[11px] tracking-widest uppercase text-black/40 mb-3">Conta</p>
          <h1
            className="text-4xl font-light tracking-tight mb-3"
            style={{ fontFamily: '"IBM Plex Sans", sans-serif' }}
          >
            Gerenciar licença
          </h1>
          <p className="text-black/50 text-sm mb-10 leading-relaxed">
            Entre com o e-mail da compra e a chave recebida (formato CDOC-…). Sem senha —
            o mesmo par usado para ativar no app.
          </p>

          {booting ? (
            <p className="text-sm text-black/40">Carregando…</p>
          ) : !license ? (
            <form
              onSubmit={onSubmit}
              className="rounded-2xl border border-black/[0.07] bg-white p-8 space-y-5"
            >
              <div>
                <label htmlFor="email" className="block text-xs tracking-wide text-black/45 mb-2">
                  E-mail
                </label>
                <input
                  id="email"
                  type="email"
                  required
                  autoComplete="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full rounded-xl border border-black/10 bg-[#F5F4F0]/50 px-4 py-3 text-sm outline-none focus:border-black/30"
                  placeholder="voce@escritorio.com"
                />
              </div>
              <div>
                <label htmlFor="key" className="block text-xs tracking-wide text-black/45 mb-2">
                  Chave de licença
                </label>
                <input
                  id="key"
                  type="text"
                  required
                  value={key}
                  onChange={(e) => setKey(e.target.value)}
                  className="w-full rounded-xl border border-black/10 bg-[#F5F4F0]/50 px-4 py-3 text-sm font-mono outline-none focus:border-black/30 tracking-wide"
                  placeholder="CDOC-XXXX-XXXX-XXXX-XXXX"
                />
              </div>
              {error && (
                <p className="text-sm text-red-700 bg-red-50 border border-red-100 rounded-xl px-4 py-3">
                  {error}
                </p>
              )}
              <button
                type="submit"
                disabled={loading}
                className="w-full rounded-xl bg-[#111] text-white text-sm py-3 hover:bg-black/80 disabled:opacity-50 transition-colors"
              >
                {loading ? "Entrando…" : "Entrar"}
              </button>
              <p className="text-xs text-black/40 text-center pt-1">
                Ainda não tem chave?{" "}
                <Link href="/#planos" className="underline hover:text-black/70">
                  Ver planos
                </Link>
              </p>
            </form>
          ) : (
            <div className="space-y-4">
              <div className="rounded-2xl border border-black/[0.07] bg-white p-8">
                <div className="flex items-start justify-between gap-4 mb-6">
                  <div>
                    <div className="text-xs tracking-widest uppercase text-black/40 mb-1">Plano</div>
                    <div
                      className="text-2xl font-light"
                      style={{ fontFamily: '"IBM Plex Sans", sans-serif' }}
                    >
                      {planLabel(license.plan)}
                    </div>
                  </div>
                  <button
                    type="button"
                    onClick={logout}
                    className="text-xs text-black/45 hover:text-black underline"
                  >
                    Sair
                  </button>
                </div>
                <dl className="grid grid-cols-1 sm:grid-cols-2 gap-4 text-sm">
                  <div>
                    <dt className="text-black/40 text-xs mb-1">E-mail</dt>
                    <dd>{license.email}</dd>
                  </div>
                  <div>
                    <dt className="text-black/40 text-xs mb-1">Chave</dt>
                    <dd className="font-mono tracking-wide">{license.key_hint}</dd>
                  </div>
                  <div>
                    <dt className="text-black/40 text-xs mb-1">Validade</dt>
                    <dd>{formatDate(license.expires_at)}</dd>
                  </div>
                  <div>
                    <dt className="text-black/40 text-xs mb-1">Dispositivos</dt>
                    <dd>
                      {license.devices.length} / {license.max_devices}
                    </dd>
                  </div>
                </dl>
              </div>

              <div className="rounded-2xl border border-black/[0.07] bg-white p-8">
                <h2
                  className="text-lg font-light mb-4"
                  style={{ fontFamily: '"IBM Plex Sans", sans-serif' }}
                >
                  Dispositivos ativos
                </h2>
                {license.devices.length === 0 ? (
                  <p className="text-sm text-black/45">Nenhum dispositivo ativado ainda.</p>
                ) : (
                  <ul className="space-y-3">
                    {license.devices.map((d) => (
                      <li
                        key={d.device}
                        className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 rounded-xl border border-black/[0.06] px-4 py-3"
                      >
                        <div>
                          <div className="text-sm font-medium">{d.device_name || "Dispositivo"}</div>
                          <div className="text-xs text-black/40 mt-0.5">
                            Ativado {formatDate(d.activated_at)} · visto {formatDate(d.last_seen)}
                          </div>
                        </div>
                        {pendingDevice === d.device ? (
                          <div className="flex gap-2">
                            <button
                              type="button"
                              disabled={loading}
                              onClick={() => deactivate(d.device)}
                              className="text-xs px-3 py-2 rounded-lg bg-red-700 text-white hover:bg-red-800 disabled:opacity-50"
                            >
                              Confirmar
                            </button>
                            <button
                              type="button"
                              onClick={() => setPendingDevice(null)}
                              className="text-xs px-3 py-2 rounded-lg border border-black/10 text-black/55"
                            >
                              Cancelar
                            </button>
                          </div>
                        ) : (
                          <button
                            type="button"
                            onClick={() => setPendingDevice(d.device)}
                            className="text-xs px-3 py-2 rounded-lg border border-black/10 text-black/55 hover:border-black/25 hover:text-black"
                          >
                            Desativar
                          </button>
                        )}
                      </li>
                    ))}
                  </ul>
                )}
                <p className="text-xs text-black/40 mt-5 leading-relaxed">
                  Desativar libera uma vaga. No próximo uso, o app pede ativação de novo nesse
                  Mac.
                </p>
              </div>

              {error && (
                <p className="text-sm text-red-700 bg-red-50 border border-red-100 rounded-xl px-4 py-3">
                  {error}
                </p>
              )}

              <p className="text-xs text-black/40 text-center">
                Precisa de ajuda?{" "}
                <a href={`mailto:${SALES_EMAIL}`} className="underline hover:text-black/70">
                  {SALES_EMAIL}
                </a>
              </p>
            </div>
          )}
        </div>
      </main>
    </div>
  )
}

"use client"

import { useEffect, useState } from "react"

const LETTERS = ["d", "i", "f", "f", "A", "I"]

const LETTER_IN_STAGGER  = 90    // ms between each letter appearing
const LETTER_IN_DUR      = 700   // duration of each letter appear transition
const HOLD_DURATION      = 300   // hold fully visible before exit
const LETTERS_IN_TOTAL   = LETTER_IN_STAGGER * (LETTERS.length - 1) + LETTER_IN_DUR + HOLD_DURATION

const LETTER_OUT_STAGGER = 55    // ms between each letter disappearing
const LETTER_OUT_DUR     = 450   // duration of each letter fade out
const LETTERS_OUT_TOTAL  = LETTER_OUT_STAGGER * (LETTERS.length - 1) + LETTER_OUT_DUR

const CURTAIN_DELAY      = LETTERS_IN_TOTAL + 100
const CURTAIN_DURATION   = 1300  // matches the CSS transition on the curtain div
const ANIM_TOTAL         = CURTAIN_DELAY + LETTERS_OUT_TOTAL + 1400

// Exported: moment the curtain finishes retracting — when the bg is fully visible
export const INTRO_DURATION_MS = CURTAIN_DELAY + CURTAIN_DURATION
// Exported: ms before curtain fully done to start hero animations (overlap for smoothness)
export const HERO_REVEAL_MS = CURTAIN_DELAY + CURTAIN_DURATION - 150

type Phase = "idle" | "in" | "out" | "done"

export function IntroAnimation({ onDone }: { onDone: () => void }) {
  const [phase, setPhase] = useState<Phase>("idle")
  const [curtainUp, setCurtainUp] = useState(false)

  useEffect(() => {
    // Tiny delay so the browser has painted before we start transitioning
    const t0 = setTimeout(() => setPhase("in"), 80)
    const t1 = setTimeout(() => setPhase("out"), LETTERS_IN_TOTAL)
    const t2 = setTimeout(() => setCurtainUp(true), CURTAIN_DELAY)
    const t3 = setTimeout(() => onDone(), HERO_REVEAL_MS)
    const t4 = setTimeout(() => setPhase("done"), ANIM_TOTAL)

    return () => { clearTimeout(t0); clearTimeout(t1); clearTimeout(t2); clearTimeout(t3); clearTimeout(t4) }
  }, [onDone])

  if (phase === "done") return null

  return (
    <div className="fixed inset-0 z-[100] pointer-events-none" aria-hidden="true">

      {/* Gradient curtain — retracts upward, revealing mountains from bottom */}
      <div
        className="absolute inset-x-0 top-0"
        style={{
          bottom: curtainUp ? "100%" : "0%",
          transition: curtainUp ? "bottom 1.3s cubic-bezier(0.76, 0, 0.24, 1)" : "none",
          background: "#f5f4f1",
        }}
      />

      {/* Brand letters → diffAI */}
      <div className="absolute inset-0 flex items-center justify-center">
        <div className="flex" style={{ gap: "0.06em" }}>
          {LETTERS.map((letter, i) => {
            const inDelay  = i * LETTER_IN_STAGGER
            const outDelay = i * LETTER_OUT_STAGGER

            // idle → invisible starting position
            const isIdle = phase === "idle"
            const isIn   = phase === "in"
            const isOut  = phase === "out"

            const opacity    = isIdle ? 0 : isIn ? 1 : 0
            const blur       = isIdle ? 36 : isIn ? 0 : 24
            const translateY = isIdle ? 48 : isIn ? 0 : -20

            const transition = isOut
              ? `opacity ${LETTER_OUT_DUR}ms cubic-bezier(0.4,0,1,1) ${outDelay}ms,
                 filter  ${LETTER_OUT_DUR}ms cubic-bezier(0.4,0,1,1) ${outDelay}ms,
                 transform ${LETTER_OUT_DUR}ms cubic-bezier(0.4,0,1,1) ${outDelay}ms`
              : isIn
              ? `opacity ${LETTER_IN_DUR}ms cubic-bezier(0.16,1,0.3,1) ${inDelay}ms,
                 filter  ${LETTER_IN_DUR}ms cubic-bezier(0.16,1,0.3,1) ${inDelay}ms,
                 transform ${LETTER_IN_DUR}ms cubic-bezier(0.16,1,0.3,1) ${inDelay}ms`
              : "none"

            return (
              <span
                key={i}
                className="font-sans font-bold text-[#111] leading-none select-none"
                style={{
                  fontSize: `calc((100vw - 64px) / ${LETTERS.length})`,
                  letterSpacing: "0.05em",
                  opacity,
                  filter: `blur(${blur}px)`,
                  transform: `translateY(${translateY}px)`,
                  transition,
                  willChange: "opacity, filter, transform",
                }}
              >
                {letter}
              </span>
            )
          })}
        </div>
      </div>

    </div>
  )
}

